class HTMLSanitizer:
    def __init__(self):
        self.allowed_tags = ['p', 'img', 'br', 'strong', 'em', 'span']
        self.allowed_attributes = {
            'img': ['src', 'alt'],
            'span': ['style']
        }
        self.allowed_entities = {
            '&': '&amp;',
            '<': '&lt;',
            '>': '&gt;',
            '"': '&quot;',
            "'": '&#039;'
        }

    def sanitize(self, html):
        stack = []
        current_tag = ''
        current_attributes = {}
        output = ''

        for char in html:
            if char == '<':
                if current_tag:
                    output += self.close_tag(current_tag, stack)
                    current_tag = ''
                stack.append(current_tag)
                current_tag = ''
            elif char == '>':
                if current_tag:
                    output += self.open_tag(current_tag, current_attributes)
                    current_attributes = {}
                current_tag = ''
            elif char == ' ':
                if current_tag:
                    current_attributes[char] = ''
            elif char == '/':
                if current_tag and current_tag not in self.allowed_tags:
                    current_tag = ''
            elif char == '>':
                if current_tag and current_tag not in self.allowed_tags:
                    current_tag = ''
            elif char in ['a', 'b', 'code', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'i', 'li', 'ol', 'p', 's', 'strike', 'u', 'ul']:
                if char not in self.allowed_tags:
                    current_tag = ''
            elif char.isalnum():
                current_tag += char
            elif char in self.allowed_attributes.get(current_tag, []):
                current_attributes[char] = ''
            elif char in self.allowed_attributes.get(current_tag, []):
                current_attributes[char] += char
            else:
                current_attributes[char] = ''

