```javascript
function sqlSanitize(input) {
    if (typeof input !== 'string') {
        throw new TypeError('Input must be a string');
    }

    let result = '';
    let i = 0;

    while (i < input.length) {
        const char = input[i];

        if (char === '\\') {
            result += char;
            i++;
        } else if (char === '\'') {
            result += '\'\'';
        } else if (char === '"'') {
            result += '\"\"';
        } else if (char === '\\n') {
            result += '\\n';
        } else if (char === '\\r') {
            result += '\\r';
        } else if (char === '\\t') {
            result += '\\t';
        } else if (char === '\\x') {
            const hex = input.substring(i + 1, i + 3);
            let ascii = parseInt(hex, 16);
            result += String.fromCharCode(ascii);
            i += 3;
        } else if (char === '\\0') {
            result += '\\0';
        } else {
            switch (char) {
                case '\\':
                case '\'':
                case '"':
                    result += '\\' + char;
                    break;
                default:
                    result += char;
            }
        }

        i++;
    }

    return result;
}
