function generateSalt() {
    let salt = '';
    const possibleCharacters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    for (let i = 0; i < 16; i++) {
        salt += possibleCharacters.charAt(Math.floor(Math.random() * possibleCharacters.length));
    }
    return salt;
}

function hashPassword(password, salt) {
    let hashedPassword = '';
    for (let i = 0; i < password.length; i++) {
        const charCode = password.charCodeAt(i);
        const saltCharCode = salt.charCodeAt(i % salt.length);
        const hashedChar = String.fromCharCode((charCode + saltCharCode) % 256);
        hashedPassword += hashedChar;
    }
    return hashedPassword;
}

function verifyPassword(password, hashedPassword, salt) {
    const expectedHashedPassword = hashPassword(password, salt);
    return expectedHashedPassword === hashedPassword;
}

function generateHashedPassword(password) {
    const salt = generateSalt();
    const hashedPassword = hashPassword(password, salt);
    return { salt, hashedPassword };
}

const password = 'mysecretpassword';
const hashedPasswordData = generateHashedPassword(password);

console.log('Hashed Password Data:', JSON.stringify(hashedPasswordData));

const isValid = verifyPassword(password, hashedPasswordData.hashedPassword, hashedPasswordData.salt);
console.log('Is Password Valid:', isValid);
