public class Main {

    public static String sanitizeString(String input) {
        StringBuilder sanitized = new StringBuilder();
        boolean inQuote = false;
        boolean inComment = false;

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            if (c == '\'' && !inComment) {
                inQuote = !inQuote;
                sanitized.append(c);
            } else if (c == '/' && i + 1 < input.length() && input.charAt(i + 1) == '*' && !inQuote) {
                inComment = true;
                sanitized.append(c);
            } else if (c == '*' && inComment && i + 1 < input.length() && input.charAt(i + 1) == '/' && !inQuote) {
                inComment = false;
                sanitized.append(c);
