                sanitized.append("%%");
                sanitized.append(c);
            } else if (c == '_' && i + 1 < input.length() && Character.isLetterOrDigit(input.charAt(i + 1))) {
                sanitized.append("_");
                sanitized.append(c);
            } else if (c == '-' && i + 1 < input.length() && Character.isLetterOrDigit(input.charAt(i + 1))) {
                sanitized.append("-");
                sanitized.append(c);
