                sanitized.append("+");
                sanitized.append(c);
            } else if (c == '=' && i + 1 < input.length() && input.charAt(i + 1) == '=') {
                sanitized.append("=");
                sanitized.append(c);
            } else if (c == '<' && i + 1 < input.length() && input.charAt(i + 1) == '=') {
                sanitized.append("<=");
