import java.net.URLDecoder;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class XSSPreventer {
    public static String preventXSS(String input) {
        String escapedInput = URLDecoder.encode(input, "UTF-8");

        // Remove HTML tags
        Pattern pattern = Pattern.compile("<.*?>");
        Matcher matcher = pattern.matcher(escapedInput);
        String cleanedInput = matcher.replaceAll("");

        // Escape special characters
        pattern = Pattern.compile("&", Pattern.CASE_INSENSITIVE);
        matcher = pattern.matcher(cleanedInput);
        cleanedInput = matcher.replaceAll("&amp;");

        pattern = Pattern.compile("<", Pattern.CASE_INSENSITIVE);
        matcher = pattern.matcher(cleanedInput);
        cleanedInput = matcher.replaceAll("&lt;");

        pattern = Pattern.compile(">", Pattern.CASE_INSENSITIVE);
        matcher = pattern.matcher(cleanedInput);
        cleanedInput = matcher.replaceAll("&gt;");

        return cleanedInput;
    }

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS')</script>";
        String escapedInput = preventXSS(userInput);
        System.out.println(escapedInput);
    }
}
