import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HtmlSanitizer {

    private static final String TAG_PATTERN = "<[^>]*>";
    private static final String SCRIPT_PATTERN = "<script>.*?</script>";
    private static final String STYLE_PATTERN = "<style>.*?</style>";
    private static final String COMMENT_PATTERN = "<!--.*?-->";
    private static final String ONCLICK_PATTERN = "on\\w+=";

    public static String sanitize(String html) {
        if (html == null) {
            return "";
        }

        Pattern pattern = Pattern.compile(TAG_PATTERN);
        Matcher matcher = pattern.matcher(html);
        html = matcher.replaceAll("");

        pattern = Pattern.compile(SCRIPT_PATTERN, Pattern.DOTALL);
        matcher = pattern.matcher(html);
        html = matcher.replaceAll("");

        pattern = Pattern.compile(STYLE_PATTERN, Pattern.DOTALL);
        matcher = pattern.matcher(html);
        html = matcher.replaceAll("");

        pattern = Pattern.compile(COMMENT_PATTERN);
        matcher = pattern.matcher(html);
        html = matcher.replaceAll("");

        pattern = Pattern.compile(ONCLICK_PATTERN, Pattern.CASE_INSENSITIVE);
        matcher = pattern.matcher(html);
        html = matcher.replaceAll("");

        return html;
    }

    public static void main(String[] args) {
        String html = "<p>Hello <script>alert('XSS')</script> World!</p>";
        System.out.println(sanitize(html));
    }
}
