import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class Main {

    public static void main(String[] args) {
        System.out.println("Enter a shell command:");
        try (BufferedReader br = new BufferedReader(new InputStreamReader(System.in))) {
            String command = br.readLine();
            safeExec(command);
        } catch (IOException e) {
            System.out.println("An error occurred: " + e.getMessage());
        }
    }

    public static void safeExec(String command) {
        Process process;
        try {
            process = Runtime.getRuntime().exec(new String[] {"bash", "-c", command});
            BufferedReader output = new BufferedReader(new InputStreamReader(process.getInputStream()));
            BufferedReader error = new BufferedReader(new InputStreamReader(process.getErrorStream()));

            StringBuilder outputBuilder = new StringBuilder();
            String line;
            while ((line = output.readLine()) != null) {
                outputBuilder.append(line).append("\n");
            }
            System.out.println("Output:");
            System.out.println(outputBuilder.toString());

            StringBuilder errorBuilder = new StringBuilder();
            while ((line = error.readLine()) != null) {
                errorBuilder.append(line).append("\n");
            }
            System.out.println("Error:");
            System.out.println(errorBuilder.toString());

            int exitCode = process.waitFor();
            if (exitCode == 0) {
                System.out.println("Command executed successfully.");
            } else {
                System.out.println("Command failed with exit code " + exitCode);
            }
        } catch (IOException | InterruptedException e) {
            System.out.println("An error occurred while executing the command: " + e.getMessage());
        }
    }
}
