    let sanitized = "";
    for (let i = 0; i < input.length; i++) {
        let char = input[i];
        if (char === "'" || char === '"' || char === "\\" || char === "%") {
            sanitized += "\\" + char;
        } else if (char === ";") {
            sanitized += "\\;";
        } else {
            sanitized += char;
        }
    }
    return sanitized;
}

function sanitizeSqlString(input) {
    return "'" + sanitizeSql(input) + "'";
}

function sanitizeSqlValue(input) {
    if (typeof input === "string") {
        return sanitizeSqlString(input);
    } else if (typeof input === "number") {
        return input.toString();
    } else if (input === null) {
        return "NULL";
    } else {
        throw new Error("Unsupported value type");
    }
}

function sanitizeSqlQuery(query, values) {
    let sanitizedQuery = "";
    let valueIndex = 0;
    for (let i = 0; i < query.length; i++) {
        let char = query[i];
        if (char === "?") {
            sanitizedQuery += sanitizeSqlValue(values[valueIndex]);
            valueIndex++;
        } else {
            sanitizedQuery += char;
        }
    }
    return sanitizedQuery;
}
