```javascript
class Sanitizer {
  constructor() {
    this.allowedTags = ['p', 'span', 'div', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'strong', 'em', 'u', 's', 'a', 'img'];
    this.allowedAttributes = {
      a: ['href', 'title'],
      img: ['src', 'alt']
    };
  }

  sanitize(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    const elements = doc.body.getElementsByTagName('*');

    for (let i = 0; i < elements.length; i++) {
      const element = elements[i];
      if (!this.allowedTags.includes(element.tagName.toLowerCase())) {
        element.outerHTML = element.innerHTML;
      } else {
        for (let j = 0; j < element.attributes.length; j++) {
          const attribute = element.attributes[j];
          if (!this.allowedAttributes[element.tagName.toLowerCase()] || !this.allowedAttributes[element.tagName.toLowerCase()].includes(attribute.name)) {
            element.removeAttribute(attribute.name);
          } else if (attribute.name === 'href' && !this.isValidUrl(attribute.value)) {
            element.removeAttribute(attribute.name);
          }
        }
      }
    }

    return doc.body.innerHTML;
  }

  isValidUrl(url) {
    try {
      const parsedUrl = new URL(url);
      return parsedUrl.protocol === 'http:' || parsedUrl.protocol === 'https:';
    } catch (e) {
      return false;
    }
  }
}

function escapeHtml(unsafe) {
  return unsafe
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

class SanitizerEncoder {
  constructor(sanitizer) {
    this.sanitizer = sanitizer;
  }

  encode(unsafe) {
    return escapeHtml(this.sanitizer.sanitize(unsafe));
  }
}

const sanitizer = new Sanitizer();
const encoder = new SanitizerEncoder(sanitizer);

const html = '<p>Hello <script>alert("XSS")</script> World!</p>';
const sanitizedHtml = encoder.encode(html);
console.log(sanitizedHtml);
