function sqlEscape(value) {
    if (value === null || value === undefined) {
        return 'NULL';
    }
    // Numbers and booleans can be returned as‑is
    if (typeof value === 'number' || typeof value === 'boolean') {
        return value.toString();
    }
    // Convert other types to string
    let str = String(value);
    // Escape backslashes first
    str = str.replace(/\\/g, '\\\\');
    // Escape single quotes by doubling them (standard SQL escaping)
    str = str.replace(/'/g, "''");
    // Escape double quotes
    str = str.replace(/"/g, '\\"');
    // Escape NUL byte
    str = str.replace(/\0/g, '\\0');
    // Escape newlines, carriage returns and tabs
    str = str.replace(/\n/g, '\\n')
             .replace(/\r/g, '\\r')
             .replace(/\t/g, '\\t');
    // Escape Control-Z (ASCII 26) which is used as a EOF marker in some DBs
    str = str.replace(/\x1a/g, '\\Z');
    // Wrap the escaped string in single quotes for safe insertion
    return `'${str}'`;
}

