function sanitize(input) {
    if (typeof input === 'string') {
        return sanitizeString(input);
    } else if (Array.isArray(input)) {
        return input.map(sanitize);
    } else if (input && typeof input === 'object') {
        const result = {};
        for (const key in input) {
            if (Object.prototype.hasOwnProperty.call(input, key)) {
                result[key] = sanitize(input[key]);
            }
        }
        return result;
    }
    return input;
}

function sanitizeString(str) {
    // Remove null bytes and other control characters
    str = str.replace(/[\0-\x1F\x7F]/g, '');
    // Trim whitespace
    str = str.trim();
    // Escape HTML special characters
    const entityMap = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#39;',
        '/': '&#x2F;'
    };
    str = str.replace(/[&<>"'\/]/g, function (s) {
        return entityMap[s];
    });
    // Remove script/style tags and their content
    str = str.replace(/<\s*(script|style)[^>]*>[\s\S]*?<\s*\/\s*\1\s*>/gi, '');
    // Remove any remaining HTML tags
    str = str.replace(/<\/?[^>]+(>|$)/g, '');
    // Remove javascript: and data: URIs in attributes
    str = str.replace(/([a-z]+)=["']\s*(javascript|data):[^"']*["']/gi, '$1=""');
    // Remove event handler attributes (on...)
    str = str.replace(/\son\w+\s*=\s*["'][^"']*["']/gi, '');
    return str;
}

function prevent_xss(str) {
    const map = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#39;'
    };
    return String(str).replace(/[&<>"']/g, function(m) { return map[m]; });
}

