public class FormValidationServlet extends HttpServlet {

    // Standard validation method (implementation may vary)
    private boolean validate_input(String input) {
        if (input == null) {
            return false;
        }
        // Example validation: non‑empty and no illegal characters
        return input.matches("^[a-zA-Z0-9_\\-@.]+$");
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        // Retrieve form data
        String username = request.getParameter("username");
        String email    = request.getParameter("email");
        String password = request.getParameter("password");

        // Validate each field using the standard validate_input() function
        boolean isUsernameValid = validate_input(username);
        boolean isEmailValid    = validate_input(email);
        boolean isPasswordValid = validate_input(password);

        // Simple handling based on validation results
        if (isUsernameValid && isEmailValid && isPasswordValid) {
            // Proceed with further processing (e.g., store in DB)
            response.setStatus(HttpServletResponse.SC_OK);
            response.getWriter().write("Form data is valid.");
        } else {
            // Return error response
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.getWriter().write("Invalid form data.");
        }
    }
