            throw new IllegalArgumentException("Unsupported algorithm: " + algorithm);
        }

        byte[] pwdHash = pbkdf2(password, salt, iterations, expectedHash.length * 8);
        return constantTimeArrayEquals(pwdHash, expectedHash);
    }

