import os
import secrets

def generate_salt(size=32):
    return secrets.token_bytes(size)

def hash_password(password, salt):
    password_bytes = password.encode('utf-8')
    hashed_password = bytearray(salt)
    for i in range(len(password_bytes)):
        hashed_password.append(password_bytes[i] ^ salt[i % len(salt)])
    for _ in range(10000):
        hashed_password = bytearray(hash((bytes(hashed_password)).decode('latin1', errors='ignore').encode('latin1')))
    return bytes(hashed_password)

def hash_password_with_salt(password):
    salt = generate_salt()
    return salt + hash_password(password, salt)

def verify_password(stored_password, provided_password):
    salt = stored_password[:32]
    return stored_password == hash_password_with_salt_and_given_salt(provided_password, salt)

def hash_password_with_salt_and_given_salt(password, salt):
    return salt + hash_password(password, salt)

def main():
    password = "mysecretpassword"
    stored_password = hash_password_with_salt(password)
    print("Stored Password: ", stored_password.hex())
    is_valid = verify_password(stored_password, password)
    print("Is password valid? ", is_valid)

if __name__ == "__main__":
