class HTMLSanitizer {
  constructor(allowedTags, allowedAttributes) {
    this.allowedTags = allowedTags;
    this.allowedAttributes = allowedAttributes;
  }

  sanitize(html) {
    const self = this;
    const sanitizedHtml = html.replace(/<(\/?)(\w+)[^>]*>/g, function(match, closing, tagName) {
      if (closing === '/') {
        return self.isAllowedTag(tagName) ? match : '';
      } else {
        return self.sanitizeTag(match, tagName);
      }
    });
    return sanitizedHtml.replace(/&/g, '&amp;')
                        .replace(/</g, '&lt;')
                        .replace(/>/g, '&gt;')
                        .replace(/"/g, '&quot;')
                        .replace(/'/g, '&#x27;');
  }

  isAllowedTag(tagName) {
    return this.allowedTags.includes(tagName.toLowerCase());
  }

  sanitizeTag(match, tagName) {
    if (!this.isAllowedTag(tagName)) return '';

    const attributeRegex = /\b(\w+)\s*=\s*"([^"]*)"/g;
    let attributes = '';
    let attributeMatch;

    while ((attributeMatch = attributeRegex.exec(match)) !== null) {
      const attributeName = attributeMatch[1];
      const attributeValue = attributeMatch[2];

      if (this.isAllowedAttribute(tagName, attributeName)) {
        attributes += ` ${attributeName}="${this.escapeAttribute(attributeValue)}"`;
      }
    }

    return `<${tagName}${attributes}>`;
  }

  isAllowedAttribute(tagName, attributeName) {
    const allowedAttributesForTag = this.allowedAttributes[tagName.toLowerCase()];
    return allowedAttributesForTag && allowedAttributesForTag.includes(attributeName.toLowerCase());
  }

  escapeAttribute(value) {
    return value.replace(/&/g, '&amp;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#x27;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;');
  }
}

