function encrypt_data(data, key) {
    let encrypted_data = "";
    for (let i = 0; i < data.length; i++) {
        let charCode = data.charCodeAt(i);
        let keyCode = key.charCodeAt(i % key.length);
        let encryptedCharCode = charCode + keyCode;
        encrypted_data += String.fromCharCode(encryptedCharCode);
    }
    return encrypted_data;
}

function decrypt_data(encrypted_data, key) {
    let decrypted_data = "";
    for (let i = 0; i < encrypted_data.length; i++) {
        let charCode = encrypted_data.charCodeAt(i);
        let keyCode = key.charCodeAt(i % key.length);
        let decryptedCharCode = charCode - keyCode;
        decrypted_data += String.fromCharCode(decryptedCharCode);
    }
    return decrypted_data;
}

