const sanitizeHtml = require('sanitize-html');

class UserRegistration {
  constructor(username, email, password) {
    this.username = username;
    this.email = email;
    this.password = password;
  }

  securePassword() {
    const salt = crypto.randomBytes(16).toString('hex');
    const hashedPassword = crypto.pbkdf2Sync(this.password, salt, 1000, 64, 'sha512').toString('hex');
    return { salt, hashedPassword };
  }

  validateEmail() {
    return validator.isEmail(this.email);
  }

  sanitizeInput(input) {
    return sanitizeHtml(input, {
      allowedTags: [],
      allowedAttributes: {}
    });
  }

  register() {
    this.username = this.sanitizeInput(this.username);
    this.email = this.sanitizeInput(this.email);

    if (!this.validateEmail()) {
      throw new Error('Invalid email');
    }

    const { salt, hashedPassword } = this.securePassword();
    // Save to database
    console.log(`Username: ${this.username}`);
    console.log(`Email: ${this.email}`);
    console.log(`Salt: ${salt}`);
    console.log(`Hashed Password: ${hashedPassword}`);
  }
}

// Example usage
const registration = new UserRegistration('testUser', 'test@example.com', 'password123');
registration.register();
