public class HtmlSanitizer {
    private static final Pattern[] tagsToRemove = new Pattern[] {
        Pattern.compile("<script>.*?</script>", Pattern.DOTALL),
        Pattern.compile("<style>.*?</style>", Pattern.DOTALL),
        Pattern.compile("<iframe.*?>.*?<\\/iframe>", Pattern.DOTALL),
        Pattern.compile("<object.*?>.*?<\\/object>", Pattern.DOTALL),
        Pattern.compile("<embed.*?>.*?<\\/embed>", Pattern.DOTALL),
        Pattern.compile("<applet.*?>.*?<\\/applet>", Pattern.DOTALL)
    };

    private static final Pattern[] attributesToRemove = new Pattern[] {
        Pattern.compile("on\\w+\\s*=\\s*[^>\\s\"]+"),
        Pattern.compile("javascript:\\s*[^>\\s\"]+")
    };

    public static String sanitize(String html) {
        // Remove disallowed tags
        for (Pattern pattern : tagsToRemove) {
            html = html.replaceAll(pattern.pattern(), "");
        }

        // Remove disallowed attributes
        for (Pattern pattern : attributesToRemove) {
            html = html.replaceAll(pattern.pattern(), "");
        }

        // Escape special characters
        html = html.replaceAll("&", "&amp;");
        html = html.replaceAll("<", "&lt;");
        html = html.replaceAll(">", "&gt;");
        html = html.replaceAll("\"", "&quot;");
        html = html.replaceAll("'", "&#x27;");

