public class Main {

    public static String encrypt_data(String data, int shift) {
        StringBuilder encryptedData = new StringBuilder();

        for (char c : data.toCharArray()) {
            if (Character.isLetter(c)) {
                char base = Character.isUpperCase(c) ? 'A' : 'a';
                encryptedData.append((char) ((c - base + shift) % 26 + base));
            } else {
                encryptedData.append(c);
            }
        }

        return encryptedData.toString();
    }

    public static String decrypt_data(String encryptedData, int shift) {
        return encrypt_data(encryptedData, 26 - shift);
    }

    public static void main(String[] args) {
        String data = "Hello, World!";
        int shift = 3;

        String encryptedData = encrypt_data(data, shift);
        System.out.println("Encrypted Data: " + encryptedData);

        String decryptedData = decrypt_data(encryptedData, shift);
        System.out.println("Decrypted Data: " + decryptedData);
    }
}
