import os
import hmac
import struct

def _pbkdf2(password, salt, iterations, dklen):
    password = password.encode('utf-8')
    salt = salt.encode('utf-8')
    dkl = b''
    for block in range(1, (dklen + 19) // 20):
        U = hmac.new(password, salt + struct.pack('>I', block), 'sha256').digest()
        T = U
        for _ in range(1, iterations):
            U = hmac.new(password, U, 'sha256').digest()
            T = bytes(a ^ b for a, b in zip(T, U))
        dkl += T
    return dkl[:dklen]

def hash_password(password, salt=None, iterations=100000):
    if salt is None:
        salt = os.urandom(16).hex()
    dk = _pbkdf2(password, salt, iterations, 32)
    return f"{iterations}${salt}${dk.hex()}"

def verify_password(password, hashed):
    its, salt, _ = hashed.split('$')
    return hmac.compare_digest(hashed, hash_password(password, salt, int(its)))

