                sb.append("&#x27;");
            } else if (c == '/') {
                sb.append("&#x2F;");
            } else if (c >= 0x7F) {
                sb.append(REPLACEMENT);
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }

