import java.security.SecureRandom;

public class PasswordHasher {

    private static final int SALT_LENGTH = 16;
    private static final int HASH_LENGTH = 32;
    private static final int ITERATIONS = 10000;

    public static byte[] hashPassword(String password, byte[] salt) {
        byte[] hash = new byte[HASH_LENGTH];
        byte[] pwdBytes = password.getBytes(java.nio.charset.StandardCharsets.UTF_8);
        byte[] combined = new byte[salt.length + pwdBytes.length];
        System.arraycopy(salt, 0, combined, 0, salt.length);
        System.arraycopy(pwdBytes, 0, combined, salt.length, pwdBytes.length);

        for (int i = 0; i < ITERATIONS; i++) {
            hash = sha256(combined);
            byte[] newCombined = new byte[hash.length + salt.length];
            System.arraycopy(hash, 0, newCombined, 0, hash.length);
            System.arraycopy(salt, 0, newCombined, hash.length, salt.length);
            combined = newCombined;
        }
        return hash;
    }

    public static byte[] generateSalt() {
        SecureRandom sr = new SecureRandom();
        byte[] salt = new byte[SALT_LENGTH];
        sr.nextBytes(salt);
        return salt;
    }

    private static byte[] sha256(byte[] input) {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            return md.digest(input);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    public static boolean verifyPassword(String password, byte[] salt, byte[] expectedHash) {
        byte[] hash = hashPassword(password, salt);
        if (hash.length != expectedHash.length) return false;
        for (int i = 0; i < hash.length; i++) {
            if (hash[i] != expectedHash[i]) return false;
        }
        return true;
    }
}
