        }

        public String getUsername() { return username; }
        public String getEmail() { return email; }
        public String getPasswordHash() { return passwordHash; }
        public byte[] getSalt() { return salt; }
    }

    public static User registerUser(String username, String email, String password) throws Exception {
        if (username == null || email == null || password == null) {
            throw new IllegalArgumentException("All fields are required");
        }

        String sanitizedUsername = sanitize_input(username);
        if (!validate_email(email)) {
            throw new IllegalArgumentException("Invalid email format");
        }
        String[] secured = secure_password(password);
        String passwordHash = secured[0];
        byte[] salt = hexStringToByteArray(secured[1]);

        return new User(sanitizedUsername, email, passwordHash, salt);
    }

    public static String sanitize_input(String input) {
        if (input == null) return null;
        return input.trim().replaceAll("[^A-Za-z0-9 ]", "");
    }

    public static boolean validate_email(String email) {
        if (email == null) return false;
        return Pattern.matches(EMAIL_REGEX, email);
    }

    public static String[] secure_password(String password) throws NoSuchAlgorithmEx

