public class SqlEscaper {
    /**
     * Escapes characters in a string to make it safe for inclusion in an SQL statement.
     * This implementation doubles single quotes and backslashes.
     *
     * @param input the raw user input
     * @return the escaped string suitable for use in an SQL query
     */
    public static String sql_escape(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder(input.length() * 2);
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '\'') {
                // Escape single quote by doubling it
                escaped.append("''");
            } else if (c == '\\') {
                // Escape backslash by doubling it
                escaped.append("\\\\");
            } else {
                escaped.append(c);
            }
        }
        return escaped.toString();
    }
}

function escape_html(str) {
    if (str == null) return '';
    const map = {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#39;'
    };
    return String(str).replace(/[&<>"']/g, function(m) {
        return map[m];
    });
}
